146	        />
147	        <FormGroup
148	          fieldId="k8s-resource-interval-selection"
149	          label={t('Kubernetes object replication interval')}
150	        >
151	          <FormHelperText>
152	            <HelperText>
153	              <HelperTextItem>
154	                {t('Define the interval for Kubernetes object replication')}
155	              </HelperTextItem>
156	            </HelperText>
157	          </FormHelperText>
158	          <RequestSizeInput
159	            name={t('Replication interval')}
160	            onChange={setInterval}
161	            dropdownUnits={SyncScheduleFormat}
162	            defaultRequestSizeUnit={unitVal}
163	            defaultRequestSizeValue={interval.toString()}
164	            minValue={MIN_VALUE}
165	            isInputDisabled={isDisable}
166	          />
167	        </FormGroup>
168	      </FormSection>
169	    </Form>
170	  );
171	};
